let audioOn=true,lastSoundAt=-1,scenePulse=0,lastMidiEvent=0,lastButton="--";
let playerX=960,playerDepth=.7,playerVelocityX=0,playerVelocityDepth=0,playerFacing=1,cameraX=0,runPhase=0;
